import ExpoLocationGeofencing from './ExpoLocationGeofencing';
import { GeofencingCallback, GeofencingRegion } from './Geofencing.types';

export async function startTaskAsync(name: string, regions: GeofencingRegion[] = []) {
  return ExpoLocationGeofencing.startTaskAsync(name, regions);
}

export async function stopTaskAsync(name: string) {
  return ExpoLocationGeofencing.stopTaskAsync(name);
}

export async function hasTaskStartedAsync(name: string): Promise<boolean> {
  return ExpoLocationGeofencing.hasTaskStartedAsync(name);
}

export async function addCallbackAsync(
  region: GeofencingRegion,
  callback: GeofencingCallback
): Promise<string> {
  return ExpoLocationGeofencing.addCallbackAsync(region, callback);
}

export async function removeCallbackAsync(id: GeofencingRegion['id']): Promise<boolean> {
  return ExpoLocationGeofencing.removeCallbackAsync(id);
}
